import{_ as a,o as n,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"General SEO Compatibility","description":"","frontmatter":{"title":"General SEO Compatibility","slug":"general-seo-compatibility"},"headers":[],"relativePath":"marketer-hub/general-seo-compatibility.md","filePath":"marketer-hub/general-seo-compatibility.md"}'),s={name:"marketer-hub/general-seo-compatibility.md"};function r(i,e,l,c,h,p){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch has invested a lot of time and effort to ensure that we only help with SEO and search rankings while delivering our value. We&#39;ve very thoughtfully designed how we treat Google and other search engine bots that crawl links to ensure that SEO juice is properly passed on to your website domain and not ours.</p><h2 id="branch-redirects-don-t-affect-seo-or-rankings" tabindex="-1">Branch Redirects Don’t Affect SEO or Rankings <a class="header-anchor" href="#branch-redirects-don-t-affect-seo-or-rankings" aria-label="Permalink to &quot;Branch Redirects Don’t Affect SEO or Rankings&quot;">​</a></h2><p>Commonly, you&#39;ll want to put Branch Links on social and other public platforms to get the benefit of Branch&#39;s deep linking and attribution. You might configure your Branch link to send your users to the website when the app is not installed by using <code>$fallback\\_url</code> or one of the platform fallbacks like <code>$desktop\\_url</code> or <code>$ios\\_url</code>.</p><p>There&#39;s no need to worry about SEO in this case. Branch uses HTTP 307 redirects to fallback to your website when the app is not installed and a Google representative has <a href="http://searchengineland.com/google-no-pagerank-dilution-using-301-302-30x-redirects-anymore-254608" target="_blank" rel="noreferrer">commented publicly</a> that these do not harm SEO or rankings.</p><h2 id="best-practices-for-using-branch-to-enhance-seo" tabindex="-1">Best Practices for Using Branch to Enhance SEO <a class="header-anchor" href="#best-practices-for-using-branch-to-enhance-seo" aria-label="Permalink to &quot;Best Practices for Using Branch to Enhance SEO&quot;">​</a></h2><p>If you&#39;re not using using <code>$fallback_url</code> or one of the platform fallbacks like <code>$desktop_url</code> or <code>$ios_url</code> to redirect users, you can still configure your Branch Links to contribute SEO juice to a website. You merely need to configure the <code>$canonical_url</code> field of the link to the web URL you&#39;d like us to send to search engine bots. This doesn&#39;t affect redirect behavior but does affect SEO.</p><p>This can be set via the native libraries while using the BUO as shown below. For other platforms, you can see the appropriate code in the following docs.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchUniversalObject *branchUniversalObject = [[BranchUniversalObject alloc] </span></span>
<span class="line"><span>initWithCanonicalIdentifier:@&quot;item/12345&quot;];</span></span>
<span class="line"><span>branchUniversalObject.canonicalUrl = @&quot;https://example.com/item/12345&quot;;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let branchUniversalObject: BranchUniversalObject = </span></span>
<span class="line"><span>BranchUniversalObject(canonicalIdentifier: &quot;item/12345&quot;)</span></span>
<span class="line"><span>branchUniversalObject.canonicalUrl = &quot;https://example.com/item/12345&quot;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> BranchUniversalObject branchUniversalObject = new BranchUniversalObject()</span></span>
<span class="line"><span>                .setCanonicalIdentifier(&quot;item/12345&quot;)</span></span>
<span class="line"><span>                .setCanonicalUrl(&quot;https://example.com/item/12345&quot;)</span></span></code></pre></div><h2 id="journeys-banners-and-other-web-integrations" tabindex="-1">Journeys Banners and Other Web Integrations <a class="header-anchor" href="#journeys-banners-and-other-web-integrations" aria-label="Permalink to &quot;Journeys Banners and Other Web Integrations&quot;">​</a></h2><p>The other common concern is around Branch&#39;s web products such as <a href="./journeys-overview.html">Journeys banners</a> or the <a href="./help.branch.io/developers-hub/docs/web-sdk-overview.html">web library</a>. After deploying your banners to the wild, you can check your Branch-integrated site using Google&#39;s <a href="https://developers.google.com/speed/pagespeed/" target="_blank" rel="noreferrer">Page Speed analyzer.</a> You&#39;ll be pleased to know that Branch is fully optimized.</p><p>You&#39;ll find that all assets such as images and text are compressed and optimized for page loads speed. Plus, our static assets are cached in our CDN to deliver fast load times globally. We won&#39;t be a hindrance to your site performance.</p>`,14)])])}const b=a(s,[["render",r]]);export{u as __pageData,b as default};
